40	async function request<T>(
41	  path: string,
42	  options: RequestInit = {},
43	  session?: Session,
44	): Promise<T> {
45	  const headers: Record<string, string> = {
46	    ...(options.headers as Record<string, string>),
47	  };
48	
49	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
50	    headers["Content-Type"] = "application/json";
51	  }
52	
53	  if (session?.agentId) {
54	    headers["X-Bayes-Agent-Id"] = session.agentId;
55	  }
56	
57	  const res = await fetch(`${API_BASE}${path}`, {
58	    ...options,
59	    headers,
60	  });
61	
62	  const body = await res.json();
63	
64	  if (!res.ok) {
65	    const err = body as ApiError;
66	    throw new BayesApiError(
67	      res.status,
68	      err.error?.code ?? "unknown_error",
69	      err.error?.details ?? {},
70	    );
71	  }
72	
73	  return body as T;
74	}
